            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-f3743d56af9c49588a703a5929ea9767/Components/UserActivityTracker.razor.js");
            await _module.InvokeVoidAsync("init", _dotNetRef, TimeoutSeconds * 1000);
        }
    }

    [JSInvokable]
    public async Task NotifyIdle()
    {
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task NotifyActive()
    {
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
